var srcSize = src.Width;
var border = (int)(srcSize * borderRatio);
// Map output pixel to source using 9-slice logic
result.ParallelForEachPixel((x, y) =>
{
    var nx = x / (float)size * outW;
    var ny = y / (float)size * outH;
    int srcX, srcY;
    // X mapping
    if (nx < border) srcX = (int)nx;
    else if (nx > outW - border) srcX = srcSize - (int)(outW - nx) - 1;
    else
    {
        var t = (nx - border) / Math.Max(1, outW - 2 * border);
        srcX = border + (int)(t * (srcSize - 2 * border));
    }
    // Y mapping
    if (ny < border) srcY = (int)ny;
    else if (ny > outH - border) srcY = srcSize - (int)(outH - ny) - 1;
    else
    {
        var t = (ny - border) / Math.Max(1, outH - 2 * border);
        srcY = border + (int)(t * (srcSize - 2 * border));
    }
    srcX = Math.Clamp(srcX, 0, srcSize - 1);
    srcY = Math.Clamp(srcY, 0, srcSize - 1);
    var (r, g, b, a) = src.GetPixel(srcX, srcY);
    result.SetPixel(x, y, r, g, b, a);
